INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('28b4c25864b4d1c8', 'WY', '["federal","state","county"]', 'ballot_access', 'Does Wyoming have an open or closed primary?', '["Wyoming closed primary rules","Do I have to register with a party to vote in the WY primary?","Can unaffiliated voters participate in the Wyoming primary?"]', 'Wyoming has a closed primary system. Under W.S. 22-5-212, voters must be registered with a political party to vote in that party''s primary. Voters who wish to change their party affiliation must do so no later than 96 days before the primary election. For the August 18, 2026 primary, the strict affiliation change deadline is May 13, 2026.', 'https://sos.wyo.gov/Elections/', 'Wyoming Secretary of State - Elections', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('cd75551589019d06', 'WY', '["state"]', 'ballot_access', 'What is the threshold to be a recognized major or minor party in Wyoming?', '["Major vs minor party Wyoming","Wyoming political party recognition threshold","How many major parties in WY?"]', 'Under W.S. 22-1-102, a ''Major party'' is one whose candidate for U.S. House, Governor, or Secretary of State received at least 10% of the total votes cast for that office in the last general election. A ''Minor party'' must have received between 2% and 10%. A ''Provisional party'' receives under 2% but filed a valid petition. Minor and provisional parties nominate candidates by convention, not via the state primary.', 'https://sos.wyo.gov/Elections/Docs/PoliticalParties.pdf', 'W.S. 22-1-102', '2026-04-21', 'static', 'statute_citation', 'Political parties', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('55fe2ff0f22b8d78', 'WY', '["federal","state","county"]', 'filing_requirements', 'What is the candidate filing deadline for Wyoming in 2026?', '["When do candidates file for office in Wyoming?","Wyoming filing week dates 2026","May filing deadline WY"]', 'For major party candidates seeking nomination in the 2026 primary, the filing period runs from May 14 to May 29, 2026. Candidates must file an application for nomination and pay the required filing fee (e.g., $750 for federal, $300 for statewide, $100 for legislative) with the Secretary of State or County Clerk by 5:00 p.m. on May 29.', 'https://sos.wyo.gov/Elections/', 'Wyoming Secretary of State', '2026-04-21', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('4ab06d7e92966fc0', 'WY', '["federal","state","county"]', 'filing_requirements', 'Can a candidate file by petition to waive the filing fee in Wyoming?', '["Wyoming filing fee waiver petition","Petition in lieu of filing fee WY","Does Wyoming allow you to bypass the filing fee?"]', 'No. Wyoming law requires all major party candidates to pay the statutory filing fee (W.S. 22-5-208) when submitting their application for nomination. There is no standard ''petition in lieu of filing fee'' option to access the major party primary ballot in Wyoming.', 'https://sos.wyo.gov/Elections/CandidateFiling.aspx', 'Wyoming Secretary of State - Candidate Filing', '2026-04-21', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('1dc2cf4f5fb443ea', 'WY', '["federal","state","county"]', 'ballot_access', 'How do independent candidates access the general election ballot in Wyoming?', '["Independent candidate petition threshold Wyoming","Wyoming non-party candidate petition deadline","How to run for office without a party in WY"]', 'Independent candidates must file a petition for nomination by the day before the primary election (August 17, 2026). Under W.S. 22-5-304, the petition must contain signatures from registered voters equal to at least 2% of the total number of votes cast for the office of U.S. Representative in the last general election in the applicable district or state.', 'https://sos.wyo.gov/Elections/Docs/Independent_Candidates.pdf', 'W.S. 22-5-304', '2026-04-21', 'per_cycle', 'statute_citation', 'Independent candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('509ec7a94bea2833', 'WY', '["federal","state","county"]', 'ballot_access', 'What are the rules for write-in candidates in Wyoming?', '["Do write-in votes count in WY?","Wyoming write-in candidate registration","Declaration of intent write-in Wyoming"]', 'A write-in candidate can win a partisan primary if they receive at least 25 write-in votes and the write-in votes equal at least the number of signatures that would have been required on a petition for that office. The winning write-in candidate must accept the nomination and pay the standard filing fee within 5 days of certification to appear on the general election ballot.', 'https://sos.wyo.gov/Elections/CandidateFiling.aspx', 'Wyoming Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'Write-in candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('d8e8b6b82c58b771', 'WY', '["federal","state","county"]', 'ballot_access', 'Does Wyoming have a sore loser law?', '["Can I run as an independent if I lose the WY primary?","Wyoming sore loser statute","General election ballot access after primary defeat WY"]', 'Yes. Under W.S. 22-5-301, a candidate who ran unsuccessfully for a major party''s nomination in the primary election is prohibited from running as an independent candidate for the same office in the subsequent general election.', 'https://sos.wyo.gov/Elections/Docs/Independent_Candidates.pdf', 'W.S. 22-5-301', '2026-04-21', 'static', 'statute_citation', 'Major party candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('31b0c8b994cdefc4', 'WY', '["federal","state","county"]', 'election_dates', 'When are the primary and general elections in Wyoming for 2026?', '["Wyoming primary date 2026","When is Election Day 2026 in Wyoming?","August primary Wyoming"]', 'The Wyoming primary election will be held on Tuesday, August 18, 2026 (the third Tuesday in August per W.S. 22-2-104), making it the latest primary election in the cycle. The general election will be held on Tuesday, November 3, 2026.', 'https://sos.wyo.gov/Elections/', 'Wyoming Secretary of State - Election Calendar', '2026-04-21', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('b718a4051410eb4e', 'WY', '["state"]', 'election_dates', 'Is Governor Mark Gordon running for re-election in 2026?', '["Wyoming Governor election 2026","Who is running for WY Governor in 2026?","NM gubernatorial term limits"]', 'No. Governor Mark Gordon (R) is term-limited and cannot run in 2026, leaving an open seat. The Wyoming Constitution (Article 4, Section 1) restricts the Governor to serving no more than 8 years in any 16-year period.', 'https://ballotpedia.org/Governor_of_Wyoming', 'Wyoming Constitution Article 4, Section 1', '2026-04-21', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('3ec640157d29594a', 'WY', '["federal"]', 'election_dates', 'Which U.S. Senate seat is up for election in Wyoming in 2026?', '["Is Cynthia Lummis up for re-election in 2026?","When is John Barrasso''s next election?","Wyoming US Senate cycle 2026"]', 'The Class 3 U.S. Senate seat currently held by Cynthia Lummis (R) is up for election in 2026. Senator John Barrasso (R) holds the Class 2 seat, was re-elected in 2024, and will not be on the ballot again until 2030.', 'https://sos.wyo.gov/Elections/', 'Wyoming Secretary of State', '2026-04-21', 'per_cycle', 'official_source_direct', 'Federal candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('4e26cd31f3a9b7ab', 'WY', '["federal"]', 'election_dates', 'How many U.S. House districts are in Wyoming for the 2026 election?', '["Wyoming congressional apportionment","Are all WY congressional seats up in 2026?","Number of US Representatives from Wyoming"]', 'Wyoming has exactly one at-large U.S. House district representing the entire state, due to its small population. This single seat will be up for election in 2026.', 'https://sos.wyo.gov/Elections/', 'Wyoming Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('a960b37104740900', 'WY', '["state"]', 'election_dates', 'Which Wyoming state legislature seats are on the 2026 ballot?', '["Are all Wyoming House seats up in 2026?","Wyoming Senate election cycle 2026","Which legislative districts are on the ballot in WY?"]', 'Following 2022 redistricting (HB 100), Wyoming has 62 House seats and 31 Senate seats. All 62 House members (2-year terms) are up for election in 2026. In the Senate (4-year terms), the 16 odd-numbered districts are on the 2026 ballot, along with any necessary special elections for vacancies in even-numbered districts.', 'https://wyoleg.gov/Legislation/2022/HB0100', 'Wyoming Legislature - HB 100', '2026-04-21', 'per_cycle', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('cfb089fa8b0fd7a6', 'WY', '["state"]', 'election_dates', 'Which statewide executive offices are up for election in Wyoming in 2026?', '["Is the Attorney General up in 2026?","WY statewide election list 2026","When is the next Secretary of State election in WY?"]', 'In addition to the Governor, the offices of Secretary of State, State Auditor, State Treasurer, and Superintendent of Public Instruction are all on the 2026 ballot. They serve four-year terms on the midterm cycle.', 'https://sos.wyo.gov/Elections/', 'Wyoming Secretary of State', '2026-04-21', 'per_cycle', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('cb87cceea0dc720a', 'WY', '["judicial"]', 'election_dates', 'Which Wyoming Supreme Court seats are on the 2026 ballot?', '["Wyoming Supreme Court election 2026","Are WY judges elected?","Next nonpartisan judicial election WY"]', 'Wyoming Supreme Court Justices do not run in contested elections. Instead, after being appointed by the Governor, they stand for nonpartisan ''Yes/No'' retention elections. In 2026, the seat currently held by Justice Robert Jarosh (and any others concluding their terms) will appear on the general election ballot for a retention vote.', 'https://www.wyocourts.gov/supreme-court/', 'Wyoming Judicial Branch', '2026-04-21', 'per_cycle', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('9dbd846c3b64b4ed', 'WY', '["state"]', 'election_dates', 'What is the schedule for Wyoming''s part-time legislative sessions?', '["When does the WY legislature meet?","Wyoming 20 day vs 40 day legislative session","Is the Wyoming legislature full time?"]', 'The Wyoming Legislature meets for a maximum of 40 legislative days in odd-numbered years for a General Session. In even-numbered years (like 2026), they meet for a shorter 20-day Budget Session focused primarily on the state budget, requiring a two-thirds vote to introduce non-budget bills.', 'https://wyoleg.gov/', 'Wyoming Legislature', '2026-04-21', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('72db260052effe03', 'WY', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Governor of Wyoming?', '["Age and residency for Wyoming Governor","Wyoming Constitution Article 4 Section 2 Governor qualifications","Who is eligible to be Governor of Wyoming?"]', 'Under Article 4, Section 2 of the Wyoming Constitution, a candidate for Governor must be a citizen of the United States, at least 30 years old, and a resident of Wyoming for at least five years preceding the election.', 'https://ballotpedia.org/Governor_of_Wyoming', 'Wyoming Constitution Article 4, Section 2', '2026-04-21', 'static', 'statute_citation', 'Gubernatorial candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('ec4406f4e4031ca4', 'WY', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for the Wyoming State Legislature?', '["Qualifications for WY State Representative","Residency requirement Wyoming State Senate","Do I have to live in my district to run in WY?"]', 'Under Article 3, Section 2 of the Wyoming Constitution, a candidate for State Senate must be at least 25 years old, and a candidate for State House must be at least 21 years old. Both must be U.S. citizens and must have resided in the county or district they wish to represent for at least 12 months next preceding their election.', 'https://sos.wyo.gov/Elections/CandidateFiling.aspx', 'Wyoming Constitution Article 3, Section 2', '2026-04-21', 'static', 'statute_citation', 'State legislative candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('633e5005d210bda2', 'WY', '["federal"]', 'candidate_eligibility', 'What are the eligibility requirements for U.S. House and Senate candidates in Wyoming?', '["US Senate residency requirements Wyoming","Age to run for Congress in Wyoming","Federal constitutional requirements for WY candidates"]', 'Federal candidates must meet U.S. Constitutional requirements: U.S. House members must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of the state when elected. U.S. Senators must be 30 years old, a U.S. citizen for 9 years, and an inhabitant of the state when elected.', 'https://sos.wyo.gov/Elections/CandidateFiling.aspx', 'Wyoming Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('7ada9283fe3b9f17', 'WY', '["state"]', 'candidate_eligibility', 'Is the Wyoming Attorney General an elected office?', '["Running for WY Attorney General","Who elects the Attorney General in Wyoming?","Legal requirements for Wyoming Attorney General"]', 'No. Unlike most states, the Wyoming Attorney General is not elected by the voters. Under W.S. 9-1-601, the Attorney General is appointed by the Governor, with the advice and consent of the State Senate, and serves at the pleasure of the Governor.', 'https://sos.wyo.gov/Elections/', 'W.S. 9-1-601', '2026-04-21', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('95dc6d098789aa34', 'WY', '["judicial"]', 'candidate_eligibility', 'Are District Court judges elected or appointed in Wyoming?', '["Wyoming District Court judge eligibility","Do judges run for election in WY?","Qualifications to run for judge in Wyoming"]', 'District Court judges in Wyoming are appointed by the Governor from a list of nominees provided by the Judicial Nominating Commission. After serving at least one year, they stand for a nonpartisan retention election. If retained, they serve six-year terms.', 'https://www.wyocourts.gov/', 'Wyoming Judicial Branch', '2026-04-21', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('9ddfeac0abf01459', 'WY', '["county"]', 'candidate_eligibility', 'What are the eligibility requirements for County Commissioner in Wyoming?', '["Qualifications for Wyoming County Commissioner","Can I run for county board in WY?","Residency rules for Wyoming commissioners"]', 'To serve as a County Commissioner, a candidate must be a qualified elector (registered voter) and a resident of the county they seek to represent. They must reside in the county throughout their four-year term per W.S. 18-3-501.', 'https://sos.wyo.gov/Elections/CandidateFiling.aspx', 'W.S. 18-3-501', '2026-04-21', 'static', 'statute_citation', 'County candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('eeb1918f5e2f9c0e', 'WY', '["state"]', 'candidate_eligibility', 'What are the term limits for Wyoming''s statewide executive officers?', '["Statewide executive term limits Wyoming","How many terms can a WY Treasurer serve?","Wyoming term limit laws"]', 'Under Article 4, Section 1 of the Wyoming Constitution, the Governor is limited to serving 8 years in any 16-year period. However, a 2004 Wyoming Supreme Court ruling struck down statutory term limits, meaning other statewide executive offices—such as State Treasurer, Auditor, Secretary of State, and Superintendent—currently face no term limits.', 'https://ballotpedia.org/Governor_of_Wyoming', 'Wyoming Constitution Article 4, Section 1', '2026-04-21', 'static', 'secondary_source', 'Statewide candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('12d5fd046609f62b', 'WY', '["state"]', 'candidate_eligibility', 'Does Wyoming have legislative term limits?', '["How many terms can a Wyoming state senator serve?","Are there term limits for the Wyoming House?","Wyoming legislature 8 in 16 term limit"]', 'No. Wyoming currently has no term limits for state legislators. While voters passed a ballot initiative in 1992 enacting term limits, the Wyoming Supreme Court struck them down in 2004, ruling that establishing term limits requires a constitutional amendment, not just a statutory change.', 'https://www.ncsl.org/about-state-legislatures/legislative-term-limits-an-overview', 'National Conference of State Legislatures - Term Limits Overview', '2026-04-21', 'static', 'secondary_source', 'State legislative candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('b0c4443752b4147f', 'WY', '["federal","state","county","municipal"]', 'voter_interaction', 'Is Wyoming a universal mail ballot state?', '["Do all voters get a mail ballot in Wyoming?","Wyoming vote-by-mail system","Are there traditional polling places in WY?"]', 'No. Wyoming is not a universal mail-out state. While some jurisdictions may use mail ballots for specific local elections, the primary method for statewide and federal elections is in-person voting. Voters who wish to vote by mail must request an absentee ballot from their county clerk.', 'https://sos.wyo.gov/Elections/State/RegisteringToVote.aspx', 'Wyoming Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('34150a0315670409', 'WY', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the deadline to request and return an absentee ballot in Wyoming?', '["When is the last day to ask for a mail ballot in WY?","Absentee ballot application deadline Wyoming","How many days before the election must I request an absentee ballot in WY?"]', 'Any registered voter may request an absentee ballot without providing an excuse. The request must be made no later than the day before the election (August 17, 2026, for the primary). To be counted, the completed absentee ballot must be received in the county clerk''s office by 7:00 p.m. on Election Day.', 'https://sos.wyo.gov/Elections/State/AbsenteeVoting.aspx', 'Wyoming Secretary of State - Absentee Voting', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('60e814f8a6f1339f', 'WY', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the voter registration deadline and does Wyoming offer same-day registration?', '["Last day to register to vote in WY","WY voter registration cutoff","Can I register to vote on Election Day in Wyoming?"]', 'The deadline to register to vote by mail or standard advance in-person registration is 14 days before an election (August 3, 2026, for the primary). However, Wyoming allows same-day registration; eligible voters may register to vote and cast a ballot in person at their polling place on Election Day.', 'https://sos.wyo.gov/Elections/State/RegisteringToVote.aspx', 'Wyoming Secretary of State - Voter Registration', '2026-04-21', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('09995333e790248a', 'WY', '["federal","state","county","municipal"]', 'voter_interaction', 'Is a photo ID required to vote in person in Wyoming?', '["Wyoming voter ID requirements","Do I need my driver''s license to vote in WY?","Safe voting photo ID Wyoming"]', 'Yes. Under a law enacted in 2021 (W.S. 22-1-102), Wyoming voters must present a valid, acceptable photo ID (such as a Wyoming driver''s license, tribal ID, U.S. passport, or military ID) to vote in person at a polling place.', 'https://sos.wyo.gov/Elections/State/VoterID.aspx', 'Wyoming Secretary of State - Voter ID', '2026-04-21', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('52eb034d7530eaa6', 'WY', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the electioneering buffer zone distance in Wyoming?', '["How close can I campaign to a polling place in WY?","Buffer zone around voting centers Wyoming","WY electioneering rules"]', 'Under W.S. 22-26-113, electioneering—which includes distributing campaign literature, wearing campaign apparel, or soliciting votes—is strictly prohibited within 100 yards (300 feet) of the building in which a polling place is located.', 'https://sos.wyo.gov/Elections/', 'W.S. 22-26-113', '2026-04-21', 'static', 'statute_citation', 'Campaign workers and Voters', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('521b8988c13d274e', 'WY', '["federal","state","county","municipal"]', 'voter_interaction', 'How are voting rights restored for individuals with felony convictions in Wyoming?', '["Can felons vote in Wyoming state?","Felony voting rights restoration WY","Voting on parole in Wyoming"]', 'Under W.S. 7-13-105, a person convicted of a non-violent felony automatically has their voting rights restored upon completion of their entire sentence, including probation and parole. Those convicted of violent felonies must individually petition the Governor for a restoration of rights.', 'https://sos.wyo.gov/Elections/State/RegisteringToVote.aspx', 'W.S. 7-13-105', '2026-04-21', 'static', 'statute_citation', 'Voters', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('45200efd9fa292b7', 'WY', '["federal","state","county","municipal"]', 'voter_interaction', 'How can campaigns access the Wyoming voter registration list?', '["Wyoming voter database access","How to get the voter list in WY","Cost of voter registration data Wyoming"]', 'Campaigns and political committees can request the voter registration list from the Wyoming Secretary of State. The list contains names, addresses, and party affiliations, and is provided for political purposes only. It is typically distributed electronically upon payment of a fee.', 'https://sos.wyo.gov/Elections/', 'Wyoming Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('21879f7fc59dc8d8', 'WY', '["county"]', 'voter_interaction', 'How many counties are in Wyoming, and why does it matter for campaigns?', '["Wyoming county election administration","How many county clerks in WY?","Local election control Wyoming"]', 'Wyoming has 23 counties. This is operationally critical for campaigns because elections are decentralized; county clerks manage absentee ballot processing, early voting logistics, and polling place operations within their respective jurisdictions.', 'https://sos.wyo.gov/Elections/', 'Wyoming Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('11304a2b811686d3', 'WY', '["state","county"]', 'finance_ethics', 'What are the individual contribution limits for Wyoming candidates in 2026?', '["How much can an individual donate to a WY Governor candidate?","Current campaign contribution limits for state legislature in WY","Wyoming individual donation caps 2026 election"]', 'Contrary to common belief, Wyoming DOES have individual contribution limits. For the 2026 election cycle, an individual may contribute up to $2,500 per election to a statewide candidate, and up to $1,500 per election to a State Senate or State House candidate. Primary and general elections are treated as separate elections.', 'https://www.wycampaignfinance.gov/WYCFWebApplication/Docs/WY%20HTML%20FILES/FILER%20HTML/filer_manage_contributions.html', 'Wyoming Campaign Finance limits', '2026-04-21', 'per_cycle', 'official_source_direct', 'Candidates and Donors', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('a021e4ec9521cee5', 'WY', '["state","county"]', 'finance_ethics', 'What are the PAC contribution limits to candidates in Wyoming?', '["WY PAC donation limits to candidates 2026","Political committee vs individual contribution limit Wyoming","Maximum PAC gift to state legislator WY"]', 'Political Action Committees (PACs) in Wyoming have varying limits depending on the office. A PAC may contribute an UNLIMITED amount to a statewide candidate per election. However, a PAC is limited to contributing a maximum of $5,000 per election to a State Senate or State House candidate.', 'https://www.wycampaignfinance.gov/WYCFWebApplication/Docs/WY%20HTML%20FILES/FILER%20HTML/filer_manage_contributions.html', 'Wyoming Campaign Finance limits', '2026-04-21', 'static', 'official_source_direct', 'State candidates and PACs', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('2510a9bef017afbe', 'WY', '["state","county","municipal"]', 'finance_ethics', 'Are corporate contributions permitted in Wyoming campaigns?', '["Corporate contribution ban Wyoming state","Can a business donate to my campaign in WY?","Corporate campaign finance rules Wyoming"]', 'No. Under W.S. 22-25-102, direct contributions from the treasury of any corporation, partnership, or labor union to a candidate''s campaign committee or a political party are strictly prohibited in Wyoming.', 'https://www.wycampaignfinance.gov/WYCFWebApplication/Docs/WY%20HTML%20FILES/FILER%20HTML/filer_manage_contributions.html', 'W.S. 22-25-102', '2026-04-21', 'static', 'statute_citation', 'Candidates and Businesses', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('81c4c81606f14b41', 'WY', '["state","county","municipal"]', 'finance_ethics', 'Which agency administers campaign finance tracking in Wyoming?', '["Where do I file campaign finance reports in WY?","What is the Wyoming CFIS?","Does the WY Secretary of State handle campaign finance?"]', 'Campaign finance reporting in Wyoming is administered by the Secretary of State''s office through the Wyoming Campaign Finance Information System (WYCFIS). All candidates for state, legislative, and statewide judicial offices must electronically file their reports via this portal.', 'https://www.wycampaignfinance.gov/', 'Wyoming Secretary of State - WYCFIS', '2026-04-21', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('f7d32f5912b0b701', 'WY', '["state","county","municipal"]', 'finance_ethics', 'What is the threshold for itemizing campaign contributions in Wyoming?', '["When do I have to list a donor''s name in Wyoming?","Itemization threshold campaign finance WY","Small donation reporting rules Wyoming"]', 'Under W.S. 22-25-106, candidates must itemize any contribution (including the donor''s name, address, and date) that exceeds $100. Contributions of $100 or less may be reported in the aggregate as unitemized contributions.', 'https://sos.wyo.gov/Elections/Docs/WY_Campaign_Finance_Guide.pdf', 'W.S. 22-25-106', '2026-04-21', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('7b4c115662b17a64', 'WY', '["state","county","municipal"]', 'finance_ethics', 'What is the general campaign finance reporting schedule for Wyoming candidates?', '["WY campaign finance filing dates","When are WYCFIS reports due for Wyoming primary?","Wyoming pre-primary and pre-general report deadlines"]', 'Candidates must file an itemized statement of contributions and expenditures at least 7 days, but not more than 14 days, before any primary or general election. Additionally, any contribution received or expenditure made after this report through the date of the election must be reported as an amendment within 10 days after the election.', 'https://sos.wyo.gov/Elections/Docs/WY_Campaign_Finance_Guide.pdf', 'Wyoming Secretary of State - Campaign Finance Guide', '2026-04-21', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('0eba2076f295b6fc', 'WY', '["state"]', 'finance_ethics', 'Does Wyoming provide public financing for state campaigns?', '["Public matching funds for Wyoming Governor","State funded campaigns Wyoming status","Government campaign grants Wyoming"]', 'No. Wyoming does not have a system of public financing or matching funds for political campaigns. All candidates must fund their campaigns through private contributions from individuals, PACs, and political parties within the statutory limits.', 'https://sos.wyo.gov/Elections/', 'Wyoming Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'State candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('d634a7a6ef4c15ef', 'WY', '["federal","state"]', 'redistricting', 'Who is responsible for drawing Wyoming''s legislative and congressional maps?', '["Does Wyoming use an independent redistricting commission?","Who has the authority to draw district lines in Wyoming?","Redistricting process Wyoming"]', 'In Wyoming, the state legislature has the exclusive authority to draw state legislative district maps. Because Wyoming only has one at-large congressional district, there is no congressional redistricting required. Maps are passed as standard legislation and are subject to the Governor''s veto.', 'https://wyoleg.gov/Committees/2021/J10', 'Wyoming Legislature - Joint Corporations, Elections & Political Subdivisions Committee', '2026-04-21', 'static', 'official_source_direct', 'State candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('164849bbc3e97d27', 'WY', '["state"]', 'redistricting', 'What are the legal criteria for redistricting in Wyoming?', '["Standards for drawing Wyoming district lines","Wyoming redistricting principles","Are county lines preserved in WY redistricting?"]', 'Under Wyoming law and legislative committee principles, districts must achieve population equality, be contiguous and compact, and preserve existing political subdivision boundaries (like county lines) and communities of interest as much as reasonably possible.', 'https://wyoleg.gov/Committees/2021/J10', 'Wyoming Legislature - Redistricting Principles', '2026-04-21', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('55df3085d764ee3c', 'WY', '["state"]', 'redistricting', 'Did Wyoming add legislative seats in its current district maps?', '["HB 100 Wyoming redistricting 2022","How many state senators does Wyoming have?","Are the current Wyoming maps operative for 2026?"]', 'Yes. Following the 2020 census, the legislature passed HB 100 (2022), which expanded the legislature from 60 House seats to 62 House seats, and from 30 Senate seats to 31 Senate seats. These maps are fully operative for the 2026 election cycle and currently face no systemic legal challenges.', 'https://wyoleg.gov/Legislation/2022/HB0100', 'Wyoming Legislature - HB 100', '2026-04-21', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('2c859623b44522e4', 'WY', '["state"]', 'recall_rules', 'Does Wyoming have a recall mechanism for state officials?', '["Can the Governor of Wyoming be recalled?","How to recall a state senator in WY","Statewide recall election rules New Mexico"]', 'No. Wyoming law does not provide a recall mechanism for statewide executive officers or state legislators. Recall procedures in Wyoming are extremely limited and do not apply to state-level offices.', 'https://ballotpedia.org/Laws_governing_recall_in_Wyoming', 'Laws governing recall in Wyoming', '2026-04-21', 'static', 'secondary_source', 'Statewide and legislative candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('eee1efc07b72ccc7', 'WY', '["county","municipal"]', 'recall_rules', 'What are the rules for local recall in Wyoming?', '["Wyoming county commissioner recall rules","Signature requirement local recall Wyoming","Recalling a mayor in WY"]', 'Wyoming does not generally permit the recall of county officials. Recall is statutorily restricted almost exclusively to municipal officials in cities operating under a commission form of government, making it one of the most restrictive recall states in the country.', 'https://ballotpedia.org/Laws_governing_recall_in_Wyoming', 'Laws governing recall in Wyoming', '2026-04-21', 'static', 'secondary_source', 'Local candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('10553347c56f4ea9', 'WY', '["state"]', 'ballot_access', 'What are the signature thresholds for a citizen initiative in Wyoming?', '["How to get an initiative on the WY ballot","Wyoming citizen initiative signature requirements","Geographic distribution rule for WY initiatives"]', 'Wyoming has one of the strictest initiative thresholds in the nation. Proponents must gather valid signatures equal to 15% of the total ballots cast in the previous general election. Furthermore, a strict geographic distribution is required: signatures must meet the 15% threshold in at least two-thirds (16) of Wyoming''s 23 counties.', 'https://sos.wyo.gov/Elections/Docs/2024/Signature_requirement_2025-26.pdf', 'Wyoming Secretary of State - Signature Requirements', '2026-04-21', 'per_cycle', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('61268ea01fc79663', 'WY', '["state"]', 'ballot_access', 'What is the 2026 Wyoming property tax limit initiative?', '["Wyoming Property Tax Exemption Initiative 2026","What is the homeowner property tax measure on the WY ballot?","25% property tax cut Wyoming ballot measure"]', 'The ''People''s Initiative to Limit Property Tax in Wyoming through a Homeowner''s Property Exemption'' officially qualified for the 2026 ballot after gathering over 30,000 valid signatures. It is the first citizen initiative to make the Wyoming ballot in nearly 30 years. If passed, it would exempt 25% of the first $1,000,000 of fair market value of primary residential properties from property taxes.', 'https://sos.wyo.gov/Elections/Initiatives.aspx', 'Wyoming Secretary of State - Initiatives', '2026-04-21', 'volatile', 'official_source_direct', 'Ballot measure committees and Voters', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('b024d296b109f930', 'WY', '["state"]', 'ballot_access', 'What is the threshold and process for a veto referendum in Wyoming?', '["How to refer a WY bill to the ballot","Wyoming citizen referendum rules","Veto referendum signature threshold Wyoming state"]', 'Citizens can refer a legislative act to the ballot via a veto referendum. Like an initiative, it requires signatures equal to 15% of the total ballots cast in the last general election, distributed across at least 16 counties. Signatures must be submitted within 90 days after the adjournment of the legislative session in which the bill was passed.', 'https://sos.wyo.gov/Elections/Initiatives.aspx', 'Wyoming Secretary of State - Initiatives & Referenda', '2026-04-21', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('a6f28423f05b3d69', 'WY', '["state"]', 'ballot_access', 'How does the Wyoming legislature refer a constitutional amendment to the voters?', '["Legislative referral process Wyoming","Referendum by legislature WY","Can the WY legislature put a constitutional amendment on the ballot?"]', 'The Wyoming Legislature can refer a proposed constitutional amendment to the voters by passing a joint resolution with a two-thirds supermajority vote of all elected members in both the House and the Senate. The Governor''s signature is not required.', 'https://ballotpedia.org/Amending_the_Wyoming_Constitution', 'Wyoming Constitution Article 20, Section 1', '2026-04-21', 'static', 'statute_citation', 'Legislators and Strategists', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('9bf7796210d93dc2', 'WY', '["state"]', 'ballot_access', 'What voter approval threshold is required to pass ballot measures in Wyoming?', '["Wyoming ballot measure pass threshold","Quorum rule Wyoming initiatives","Why is it hard to pass a ballot measure in WY?"]', 'Wyoming utilizes a strict ''quorum rule'' for citizen initiatives and constitutional amendments. To pass, a measure must receive a majority of ''Yes'' votes out of the total number of ballots cast in the entire election. This means a voter who casts a ballot for Governor but leaves the initiative question blank is effectively counted as a ''No'' vote against the measure.', 'https://sos.wyo.gov/Elections/Initiatives.aspx', 'Wyoming Secretary of State - Initiatives', '2026-04-21', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('81dc97cbc2a2d2cc', 'WY', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Secretary of State in Wyoming?', '["Requirements to run for WY Secretary of State","Who can run for Secretary of State in WY?","Professional requirements for WY SOS"]', 'Under Article 4, Section 11 of the Wyoming Constitution, candidates for Secretary of State must be at least 25 years old, a citizen of the United States, and a qualified elector (registered voter) of Wyoming. There are no professional degree requirements.', 'https://sos.wyo.gov/Elections/CandidateFiling.aspx', 'Wyoming Constitution Article 4, Section 11', '2026-04-21', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('c56e09168de7352c', 'WY', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for State Treasurer or State Auditor in Wyoming?', '["Eligibility for Wyoming State Treasurer","Who can run for State Auditor in WY?","Qualifications for WY financial officers"]', 'Candidates for State Treasurer and State Auditor share the same constitutional requirements as the Secretary of State: they must be at least 25 years old, U.S. citizens, and qualified electors of Wyoming. No specific financial or CPA certifications are constitutionally mandated.', 'https://sos.wyo.gov/Elections/CandidateFiling.aspx', 'Wyoming Constitution Article 4, Section 11', '2026-04-21', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('ef2fcd046516be57', 'WY', '["state"]', 'candidate_eligibility', 'Is the Wyoming Superintendent of Public Instruction elected, and what are the qualifications?', '["Running for WY Superintendent of Schools","Who elects the Superintendent of Public Instruction in Wyoming?","Department of Education leadership WY"]', 'Yes, the Superintendent of Public Instruction is one of five statewide elected executives in Wyoming. Under W.S. 22-5-204, candidates must be at least 25 years old, a U.S. citizen, and a registered voter. Statutory law also specifies they must possess academic and professional education equivalent to graduation from a standard university or college.', 'https://sos.wyo.gov/Elections/CandidateFiling.aspx', 'Wyoming Secretary of State - Candidate Qualifications', '2026-04-21', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('63df1c4e4bf238d5', 'WY', '["municipal"]', 'candidate_eligibility', 'What are the eligibility requirements for a school board candidate in Wyoming?', '["Run for school board Wyoming requirements","Who can be a school trustee in WY?","School board residency rules Wyoming"]', 'To run for a local school district board of trustees in Wyoming, a candidate must be a qualified elector (registered voter) and a resident of the specific school district they seek to represent at the time of the election.', 'https://sos.wyo.gov/Elections/CandidateFiling.aspx', 'Wyoming Secretary of State - Local Candidate Qualifications', '2026-04-21', 'static', 'official_source_direct', 'School board candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('e6f6b6630b45ec3c', 'WY', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the ballot signature cure process for absentee ballots in Wyoming?', '["How to fix a rejected signature in WY","Wyoming ballot cure process","Missing signature on WY mail ballot"]', 'Wyoming is one of the few states that does not have a statutory absentee ballot signature curing process. If an absentee ballot envelope is missing a signature or is otherwise defective, election officials are not required to provide the voter an opportunity to ''cure'' or fix the ballot before it is rejected.', 'https://www.vote411.org/wyoming', 'Vote411 - Wyoming Voting Information', '2026-04-21', 'static', 'secondary_source', 'Voters and Campaigns', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('f022d9d6d6566d33', 'WY', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the deadlines for military and overseas (UOCAVA) voters in Wyoming?', '["When are military ballots due in Wyoming?","UOCAVA return deadline WY","Overseas voting rules Wyoming state"]', 'Under UOCAVA, ballots are transmitted to military and overseas voters 45 days before an election. Voted ballots must be received by the county clerk''s office no later than 7:00 p.m. on Election Day to be counted.', 'https://sos.wyo.gov/Elections/State/AbsenteeVoting.aspx', 'Wyoming Secretary of State - Military & Overseas Voters', '2026-04-21', 'static', 'official_source_direct', 'UOCAVA voters', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('97ee53c6e2c7111b', 'WY', '["federal","state","county","municipal"]', 'voter_interaction', 'When are provisional ballots used in Wyoming?', '["What is a provisional ballot in WY?","Voting without ID Wyoming","When do election workers issue provisional ballots?"]', 'Provisional ballots are issued if a voter''s name is not in the poll book, if they fail to produce required identification, or if records show they were issued an absentee ballot but wish to vote in person. To be counted, the voter must provide the required information/ID to the county clerk by the close of business on the day following the election.', 'https://sos.wyo.gov/Elections/', 'Wyoming Secretary of State - Elections', '2026-04-21', 'static', 'official_source_direct', 'Voters and Poll Watchers', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('73b50ba129816994', 'WY', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Wyoming have Automatic Voter Registration (AVR) at the DMV?', '["Is registration automatic at the Wyoming MVD?","WY motor voter automatic registration","Do I have to register to vote if I get a WY driver''s license?"]', 'No. Wyoming is historically exempt from the federal National Voter Registration Act (Motor Voter law) because it offers Election Day registration. Therefore, it does not offer Automatic Voter Registration (AVR) at the Department of Transportation.', 'https://sos.wyo.gov/Elections/State/RegisteringToVote.aspx', 'Wyoming Secretary of State - Voter Registration', '2026-04-21', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('6ac5fb5f6b18e97d', 'WY', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Wyoming offer Online Voter Registration?', '["Can I register to vote online in WY?","Wyoming electronic voter registration","WY SOS online registration portal"]', 'No. Wyoming does not have an online voter registration system. Voters must register in person at their county clerk''s office, by mail (with a notarized form), or at the polls on Election Day.', 'https://sos.wyo.gov/Elections/State/RegisteringToVote.aspx', 'Wyoming Secretary of State - Voter Registration', '2026-04-21', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('9853187a1f7e2f41', 'WY', '["federal","state","county","municipal"]', 'voter_interaction', 'How does Wyoming maintain its voter registration lists?', '["WY voter list maintenance rules","How are inactive voters handled in Wyoming?","Wyoming voter roll cleaning process"]', 'Wyoming maintains its voter registry (WyoReg) primarily through a post-election purge process. Under state law, any registered voter who fails to vote in a general election is sent a notice and, if they do not respond, has their registration canceled (purged) and must re-register to vote in future elections.', 'https://sos.wyo.gov/Elections/', 'Wyoming Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('628fb827f113c093', 'WY', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Wyoming have early voting?', '["Can I vote early in person in WY?","Wyoming early voting dates 2026","In-person absentee voting Wyoming"]', 'Wyoming does not have separate, dedicated ''early voting'' polling locations. Instead, it offers ''in-person absentee voting.'' Voters may go to their county clerk''s office during standard business hours beginning 28 days before the election to cast an absentee ballot in person. This period ends the day before Election Day.', 'https://sos.wyo.gov/Elections/State/AbsenteeVoting.aspx', 'Wyoming Secretary of State - Absentee Voting', '2026-04-21', 'per_cycle', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('a078afea7846d5f9', 'WY', '["federal","state","county"]', 'runoff_rules', 'Does Wyoming use runoff elections for close races?', '["Are there runoffs in Wyoming primaries?","How are tied elections decided in Wyoming?","Tie-breaker rules Wyoming elections"]', 'No. Wyoming does not hold runoff elections for state or federal offices. The candidate with a plurality of the vote wins. In the event of an exact tie, under W.S. 22-16-119, the canvassing board determines the winner by casting lots (e.g., drawing names or a coin toss).', 'https://sos.wyo.gov/Elections/', 'W.S. 22-16-119', '2026-04-21', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('12204e0cd5901274', 'WY', '["state","county","municipal"]', 'runoff_rules', 'Is Ranked Choice Voting (RCV) used in Wyoming?', '["Does Wyoming use ranked choice voting?","RCV status in Wyoming 2026","Instant runoff voting WY"]', 'No. Ranked Choice Voting is not used in Wyoming for any state or local public elections. Plurality voting is the standard across the state.', 'https://sos.wyo.gov/Elections/', 'Wyoming Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('663389242e7f67ea', 'WY', '["state","county","municipal"]', 'finance_ethics', 'Are candidates prohibited from using campaign funds for personal use in Wyoming?', '["WY personal use prohibition campaign finance","Can I use campaign money for personal expenses in Wyoming?","Prohibited expenditures Wyoming WYCFIS"]', 'Yes. Under W.S. 22-25-102, campaign contributions may not be converted to the personal use of the candidate or any other person. Funds must be strictly used for campaign activities or duties related to holding office.', 'https://law.justia.com/codes/wyoming/title-22/chapter-25/section-22-25-102/', 'W.S. 22-25-102', '2026-04-21', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('fac78e21559aae4c', 'WY', '["state","county","municipal"]', 'finance_ethics', 'What disclaimer language is required on Wyoming campaign materials?', '["Wyoming ''Paid for by'' rules","Campaign ad disclaimer requirements WY","Political taglines Wyoming WYCFIS"]', 'Wyoming law requires that election literature and campaign advertising display a sponsor identification line. The disclaimer must clearly state ''Paid for by'' followed by the name of the candidate, organization, or committee funding the material.', 'https://sos.wyo.gov/Elections/Docs/WY_Campaign_Finance_Guide.pdf', 'Wyoming Secretary of State - Campaign Finance Guide', '2026-04-21', 'static', 'official_source_direct', 'All candidates and PACs', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('5c7f1d8b3c810987', 'WY', '["state","county","municipal"]', 'finance_ethics', 'When does outside spending become prohibited coordination in Wyoming?', '["WY campaign coordination rules","When is a PAC expenditure not independent in Wyoming?","Prohibition on candidate-PAC coordination WY"]', 'An expenditure is ''coordinated'' (and thus treated as an in-kind contribution subject to limits and corporate bans) if it is made in cooperation, consultation, or concert with, or at the request or suggestion of, a candidate or their campaign committee. The Secretary of State''s rules strictly define independent expenditures as those made entirely without the candidate''s involvement.', 'https://sos.wyo.gov/Elections/Docs/WY_Campaign_Finance_Guide.pdf', 'Wyoming Secretary of State - Campaign Finance Guide', '2026-04-21', 'static', 'official_source_direct', 'All candidates and IECs', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('22b533d5b44e2288', 'WY', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for late campaign finance filings in Wyoming?', '["WY WYCFIS late fee","Penalty for missing a Wyoming campaign finance deadline","Secretary of State fine for late filing WY"]', 'Under W.S. 22-25-108, failing to file a required campaign finance report on time results in a civil penalty. The fine is up to $500 per day for reports filed with the Secretary of State, and up to $200 per day for reports filed with a county clerk, accruing until the report is successfully submitted.', 'https://law.justia.com/codes/wyoming/title-22/chapter-25/section-22-25-108/', 'W.S. 22-25-108', '2026-04-21', 'static', 'statute_citation', 'All candidates and treasurers', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('6be2b725adf8db6d', 'WY', '["state","county","municipal"]', 'finance_ethics', 'When and how must a Wyoming campaign committee terminate?', '["Closing a Wyoming campaign committee","WYCFIS committee termination requirements","Final campaign finance report Wyoming"]', 'A candidate committee may terminate its WYCFIS account only when it has achieved a zero cash balance, disposed of all surplus funds legally, and resolved all outstanding debts. The committee must file a final termination report to officially close.', 'https://www.wycampaignfinance.gov/', 'Wyoming Secretary of State - WYCFIS', '2026-04-21', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('270395e71b0a88e2', 'WY', '["state","county","municipal"]', 'finance_ethics', 'What are the disclosure rules for independent expenditures in Wyoming?', '["WY independent expenditure reporting WYCFIS","Disclosure for WY independent expenditure groups","Reporting thresholds for outside spending Wyoming"]', 'Any organization or person making an independent expenditure to advocate for or against a candidate must report the expenditure in WYCFIS. These must be filed on the same schedule as candidate reports (7 days before the election).', 'https://sos.wyo.gov/Elections/Docs/WY_Campaign_Finance_Guide.pdf', 'Wyoming Secretary of State - Campaign Finance Guide', '2026-04-21', 'static', 'official_source_direct', 'Independent groups and PACs', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('7c7ea1d11e36fd68', 'WY', '["state","county","municipal"]', 'finance_ethics', 'How are in-kind contributions valued and reported in Wyoming?', '["Wyoming in-kind contribution valuation rules","Reporting non-monetary donations Wyoming campaign","Fair market value for in-kind gifts WY"]', 'In-kind contributions (donated goods, services, or equipment) must be reported in WYCFIS at their fair market value—the standard price the campaign would have paid on the open market. They must be itemized if their value exceeds the $100 reporting threshold.', 'https://sos.wyo.gov/Elections/Docs/WY_Campaign_Finance_Guide.pdf', 'Wyoming Secretary of State - Campaign Finance Guide', '2026-04-21', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('9e94ea9d30d7f9b2', 'WY', '["state","county","municipal"]', 'finance_ethics', 'Are there limits on a candidate loaning personal funds to their own campaign in Wyoming?', '["Wyoming candidate personal loan limits","Can I pay myself back for a campaign loan in WY?","Reporting candidate loans in WYCFIS"]', 'Under Wyoming law, a candidate may loan or contribute an unlimited amount of their own personal funds to their campaign. Self-funding is not subject to the individual contribution limits that apply to third parties. Loans must be properly documented in WYCFIS.', 'https://www.wycampaignfinance.gov/', 'Wyoming Campaign Finance Information System', '2026-04-21', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('b342aaa7b6d0c5d0', 'WY', '["state","county","municipal"]', 'finance_ethics', 'What can Wyoming candidates do with unexpended campaign funds?', '["What can I do with leftover campaign money in WY?","WY surplus campaign funds rules","Donating remaining campaign funds Wyoming"]', 'Unexpended campaign funds cannot be converted to personal use. They may be retained for a future campaign by the same candidate, returned pro-rata to contributors, donated to a political party, or given to a charitable organization.', 'https://sos.wyo.gov/Elections/Docs/WY_Campaign_Finance_Guide.pdf', 'Wyoming Secretary of State - Campaign Finance Guide', '2026-04-21', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('343bf7f5a6d3a37c', 'WY', '["state"]', 'finance_ethics', 'Is there a session freeze on campaign contributions for lobbyists in Wyoming?', '["Can Wyoming legislators raise money during session?","Lobbyist contribution ban WY legislature","Legislative session contribution rules Wyoming"]', 'Unlike neighboring Montana, Wyoming does not have a statutory ''session freeze'' that broadly bans legislative candidates from raising money from lobbyists during the session. However, Governor Mark Gordon issued an Executive Order in 2026 banning campaign contributions within any state buildings used by the Executive Branch.', 'https://stateandfed.com/state/wyoming/wyoming-governor-issues-executive-order-banning-campaign-contributions-in-state-buildings/', 'Wyoming Executive Order 2026-01', '2026-04-21', 'static', 'secondary_source', 'State candidates and Lobbyists', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('9e2bd10a09117a80', 'WY', '["state","county","municipal"]', 'election_dates', 'What are the polling hours on Election Day in Wyoming?', '["When do polls open in WY?","WY polling place hours","What time do polls close in Wyoming?"]', 'On Election Day, all polling places in Wyoming are open from 7:00 a.m. to 7:00 p.m. Under W.S. 22-13-101, any qualified elector who is physically in line at the polling place at 7:00 p.m. is legally permitted to cast their ballot.', 'https://sos.wyo.gov/Elections/State/VotingInformation.aspx', 'Wyoming Secretary of State - Voting Information', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('7f0226d83709b0c0', 'WY', '["county"]', 'election_dates', 'What are the terms and election cycles for county offices in Wyoming?', '["When are county sheriffs elected in WY?","Wyoming county official term lengths","Are county assessors on the 2026 ballot?"]', 'Elected county officials in Wyoming—including County Commissioners, Sheriffs, Assessors, Clerks, Coroners, and Treasurers—serve four-year terms. The vast majority of these offices are elected during the midterm election cycle, meaning they will be on the 2026 ballot.', 'https://sos.wyo.gov/Elections/', 'Wyoming Secretary of State', '2026-04-21', 'per_cycle', 'official_source_direct', 'County candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('1f03e08a46349641', 'WY', '["state","county","municipal"]', 'election_dates', 'What is the canvassing and certification timeline for Wyoming elections?', '["When are Wyoming election results official?","WY certification deadline","State Canvassing Board meeting Wyoming"]', 'County canvassing boards meet shortly after the election to certify local results. The State Canvassing Board meets to officially certify statewide and federal election results no later than the second Wednesday following the general election.', 'https://sos.wyo.gov/Elections/', 'Wyoming Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'All candidates and campaigns', 'batch_2026-05-15T17-08-24_wyoming_full_v1'),
  ('5f52bc151667b1bf', 'WY', '["federal","state"]', 'election_dates', 'When and how are special elections called in Wyoming?', '["Wyoming special election timeline","Who calls a special election to fill a US House vacancy in WY?","Filling a midterm vacancy Wyoming"]', 'Special elections to fill vacancies (such as for a U.S. House seat) are called by a proclamation from the Governor. The proclamation sets the timeline and date for the election, and major parties typically nominate their candidates via central committee selection rather than a primary.', 'https://sos.wyo.gov/Elections/', 'Wyoming Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-15T17-08-24_wyoming_full_v1')
